package com.example.mfa.service;

import com.example.mfa.model.AppUser;
import com.example.mfa.model.BackupCode;
import com.example.mfa.repository.BackupCodeRepository;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.security.SecureRandom;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;

@Service
public class BackupCodeService {

    private static final int DEFAULT_CODE_COUNT = 10;
    private static final int CODE_LENGTH = 10;
    private static final String CHARS = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";

    private final SecureRandom secureRandom = new SecureRandom();
    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;

    public BackupCodeService(BackupCodeRepository backupCodeRepository, PasswordEncoder passwordEncoder) {
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public List<String> regenerateCodes(AppUser user) {
        backupCodeRepository.deleteByUser(user);
        List<String> plainCodes = new ArrayList<>();
        for (int i = 0; i < DEFAULT_CODE_COUNT; i++) {
            String code = generateReadableCode();
            plainCodes.add(code);
            BackupCode backupCode = new BackupCode();
            backupCode.setUser(user);
            backupCode.setCodeHash(passwordEncoder.encode(code));
            backupCode.setUsed(false);
            backupCodeRepository.save(backupCode);
        }
        return plainCodes;
    }

    @Transactional
    public boolean consumeBackupCode(AppUser user, String rawCode) {
        List<BackupCode> activeCodes = backupCodeRepository.findByUserAndUsedFalse(user);
        for (BackupCode backupCode : activeCodes) {
            if (passwordEncoder.matches(normalize(rawCode), backupCode.getCodeHash())) {
                backupCode.setUsed(true);
                backupCode.setUsedAt(Instant.now());
                backupCodeRepository.save(backupCode);
                return true;
            }
        }
        return false;
    }

    private String generateReadableCode() {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < CODE_LENGTH; i++) {
            sb.append(CHARS.charAt(secureRandom.nextInt(CHARS.length())));
            if (i == 4) {
                sb.append('-');
            }
        }
        return sb.toString();
    }

    private String normalize(String code) {
        return code == null ? "" : code.trim().toUpperCase();
    }
}

package com.example.mfa.service;

import org.apache.commons.codec.binary.Base32;
import org.springframework.stereotype.Service;

import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.net.URLEncoder;
import java.nio.ByteBuffer;
import java.nio.charset.StandardCharsets;
import java.security.SecureRandom;

@Service
public class TotpService {

    private static final String HMAC_ALGORITHM = "HmacSHA1";
    private static final int SECRET_SIZE = 20;
    private static final int TIME_STEP_SECONDS = 30;
    private static final int DIGITS = 6;

    public String generateSecret() {
        byte[] buffer = new byte[SECRET_SIZE];
        new SecureRandom().nextBytes(buffer);
        return new Base32().encodeToString(buffer).replace("=", "");
    }

    public boolean verifyCode(String secret, String code) {
        if (secret == null || code == null || code.isBlank()) {
            return false;
        }
        String normalized = code.trim();
        long currentInterval = System.currentTimeMillis() / 1000L / TIME_STEP_SECONDS;
        for (int i = -1; i <= 1; i++) {
            String candidate = generateCode(secret, currentInterval + i);
            if (candidate.equals(normalized)) {
                return true;
            }
        }
        return false;
    }

    public String buildOtpAuthUrl(String issuer, String username, String secret) {
        String label = urlEncode(issuer + ":" + username);
        return "otpauth://totp/" + label + "?secret=" + urlEncode(secret) + "&issuer=" + urlEncode(issuer) + "&digits=6&period=30";
    }

    private String generateCode(String secret, long interval) {
        try {
            byte[] key = new Base32().decode(secret);
            byte[] data = ByteBuffer.allocate(8).putLong(interval).array();
            Mac mac = Mac.getInstance(HMAC_ALGORITHM);
            mac.init(new SecretKeySpec(key, HMAC_ALGORITHM));
            byte[] hash = mac.doFinal(data);
            int offset = hash[hash.length - 1] & 0xF;
            int binary =
                    ((hash[offset] & 0x7F) << 24) |
                    ((hash[offset + 1] & 0xFF) << 16) |
                    ((hash[offset + 2] & 0xFF) << 8) |
                    (hash[offset + 3] & 0xFF);
            int otp = binary % (int) Math.pow(10, DIGITS);
            return String.format("%06d", otp);
        } catch (Exception e) {
            return "";
        }
    }

    private String urlEncode(String value) {
        return URLEncoder.encode(value, StandardCharsets.UTF_8);
    }
}

package com.example.mfa.service;

import com.example.mfa.dto.AuthResponse;
import com.example.mfa.dto.BackupCodesResponse;
import com.example.mfa.dto.EnableMfaRequest;
import com.example.mfa.dto.LoginRequest;
import com.example.mfa.dto.MfaSetupResponse;
import com.example.mfa.dto.RegisterRequest;
import com.example.mfa.model.AppUser;
import com.example.mfa.repository.AppUserRepository;
import jakarta.persistence.EntityNotFoundException;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;

@Service
public class AuthService {

    private static final String ISSUER = "EnterpriseAuthSystem";

    private final AppUserRepository appUserRepository;
    private final PasswordEncoder passwordEncoder;
    private final TotpService totpService;
    private final BackupCodeService backupCodeService;

    public AuthService(AppUserRepository appUserRepository,
                       PasswordEncoder passwordEncoder,
                       TotpService totpService,
                       BackupCodeService backupCodeService) {
        this.appUserRepository = appUserRepository;
        this.passwordEncoder = passwordEncoder;
        this.totpService = totpService;
        this.backupCodeService = backupCodeService;
    }

    @Transactional
    public void register(RegisterRequest request) {
        appUserRepository.findByUsername(request.getUsername()).ifPresent(u -> {
            throw new IllegalArgumentException("Username already exists");
        });
        AppUser user = new AppUser();
        user.setUsername(request.getUsername());
        user.setPasswordHash(passwordEncoder.encode(request.getPassword()));
        user.setTotpSecret(totpService.generateSecret());
        user.setTwoFactorEnabled(false);
        appUserRepository.save(user);
    }

    @Transactional
    public MfaSetupResponse beginMfaSetup(String username) {
        AppUser user = getUser(username);
        if (user.getTotpSecret() == null || user.getTotpSecret().isBlank()) {
            user.setTotpSecret(totpService.generateSecret());
            appUserRepository.save(user);
        }
        String url = totpService.buildOtpAuthUrl(ISSUER, user.getUsername(), user.getTotpSecret());
        return new MfaSetupResponse(user.getTotpSecret(), url);
    }

    @Transactional
    public BackupCodesResponse enableMfa(String username, EnableMfaRequest request) {
        AppUser user = getUser(username);
        if (!totpService.verifyCode(user.getTotpSecret(), request.getTotpCode())) {
            throw new IllegalArgumentException("Invalid TOTP code");
        }
        user.setTwoFactorEnabled(true);
        appUserRepository.save(user);
        List<String> codes = backupCodeService.regenerateCodes(user);
        return new BackupCodesResponse(codes);
    }

    @Transactional(readOnly = true)
    public AuthResponse login(LoginRequest request) {
        AppUser user = appUserRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new IllegalArgumentException("Invalid credentials"));

        if (!passwordEncoder.matches(request.getPassword(), user.getPasswordHash())) {
            throw new IllegalArgumentException("Invalid credentials");
        }

        if (!user.isTwoFactorEnabled()) {
            return new AuthResponse(true, false, "Authenticated", "PASSWORD_ONLY");
        }

        boolean hasTotp = request.getTotpCode() != null && !request.getTotpCode().isBlank();
        boolean hasBackup = request.getBackupCode() != null && !request.getBackupCode().isBlank();

        if (!hasTotp && !hasBackup) {
            return new AuthResponse(false, true, "MFA required. Provide TOTP code or backup code.", null);
        }

        if (hasTotp && totpService.verifyCode(user.getTotpSecret(), request.getTotpCode())) {
            return new AuthResponse(true, false, "Authenticated", "TOTP");
        }

        return new AuthResponse(false, true, "Invalid MFA code", null);
    }

    @Transactional
    public AuthResponse loginWithBackupCode(LoginRequest request) {
        AppUser user = appUserRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new IllegalArgumentException("Invalid credentials"));

        if (!passwordEncoder.matches(request.getPassword(), user.getPasswordHash())) {
            throw new IllegalArgumentException("Invalid credentials");
        }

        if (!user.isTwoFactorEnabled()) {
            return new AuthResponse(true, false, "Authenticated", "PASSWORD_ONLY");
        }

        if (request.getBackupCode() == null || request.getBackupCode().isBlank()) {
            return new AuthResponse(false, true, "Backup code required", null);
        }

        boolean consumed = backupCodeService.consumeBackupCode(user, request.getBackupCode());
        if (!consumed) {
            return new AuthResponse(false, true, "Invalid backup code", null);
        }

        return new AuthResponse(true, false, "Authenticated using backup code", "BACKUP_CODE");
    }

    @Transactional
    public BackupCodesResponse regenerateBackupCodes(String username) {
        AppUser user = getUser(username);
        if (!user.isTwoFactorEnabled()) {
            throw new IllegalArgumentException("MFA must be enabled before generating backup codes");
        }
        return new BackupCodesResponse(backupCodeService.regenerateCodes(user));
    }

    private AppUser getUser(String username) {
        return appUserRepository.findByUsername(username)
                .orElseThrow(() -> new EntityNotFoundException("User not found"));
    }
}

package com.example.mfa.controller;

import com.example.mfa.dto.AuthResponse;
import com.example.mfa.dto.BackupCodesResponse;
import com.example.mfa.dto.EnableMfaRequest;
import com.example.mfa.dto.LoginRequest;
import com.example.mfa.dto.MfaSetupResponse;
import com.example.mfa.dto.RegisterRequest;
import com.example.mfa.service.AuthService;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/auth")
public class AuthController {

    private final AuthService authService;

    public AuthController(AuthService authService) {
        this.authService = authService;
    }

    @PostMapping("/register")
    @ResponseStatus(HttpStatus.CREATED)
    public void register(@Valid @RequestBody RegisterRequest request) {
        authService.register(request);
    }

    @PostMapping("/{username}/mfa/setup")
    public MfaSetupResponse setupMfa(@PathVariable String username) {
        return authService.beginMfaSetup(username);
    }

    @PostMapping("/{username}/mfa/enable")
    public BackupCodesResponse enableMfa(@PathVariable String username,
                                         @Valid @RequestBody EnableMfaRequest request) {
        return authService.enableMfa(username, request);
    }

    @PostMapping("/login")
    public AuthResponse login(@Valid @RequestBody LoginRequest request) {
        if (request.getBackupCode() != null && !request.getBackupCode().isBlank()) {
            return authService.loginWithBackupCode(request);
        }
        return authService.login(request);
    }

    @PostMapping("/{username}/backup-codes/regenerate")
    public BackupCodesResponse regenerateBackupCodes(@PathVariable String username) {
        return authService.regenerateBackupCodes(username);
    }
}

package com.example.mfa.controller;

import jakarta.persistence.EntityNotFoundException;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.MethodArgumentNotValidException;
import org.springframework.web.bind.annotation.*;

import java.util.Map;

@RestControllerAdvice
public class GlobalExceptionHandler {

    @ExceptionHandler(IllegalArgumentException.class)
    @ResponseStatus(HttpStatus.BAD_REQUEST)
    public Map<String, String> handleIllegalArgument(IllegalArgumentException ex) {
        return Map.of("error", ex.getMessage());
    }

    @ExceptionHandler(EntityNotFoundException.class)
    @ResponseStatus(HttpStatus.NOT_FOUND)
    public Map<String, String> handleNotFound(EntityNotFoundException ex) {
        return Map.of("error", ex.getMessage());
    }

    @ExceptionHandler(MethodArgumentNotValidException.class)
    @ResponseStatus(HttpStatus.BAD_REQUEST)
    public Map<String, String> handleValidation(MethodArgumentNotValidException ex) {
        return Map.of("error", "Validation failed");
    }
}

